class Buffer {
    int* data;
public:
    Buffer(int v) : data(new int(v)) {}
    Buffer(const Buffer& other) : data(new int(*other.data)) {}
    ~Buffer() { delete data; }
    friend void swap(Buffer& a, Buffer& b) noexcept {
        using std::swap;
        swap(a.data, b.data);
    }
    Buffer& operator=(Buffer other) {
        swap(*this, other);
        return *this;
    }
    int get() const { return *data; }
};

